class Solution {
public:
    int minMoves(vector<int>& nums) {
        return accumulate(nums.cbegin(), nums.cend(), 0) -
               nums.size() * *min_element(nums.cbegin(), nums.cend());
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def minMoves(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        return sum(nums) - len(nums) * min(nums)
